  ('pukao-d0d1b9a2-moex-00307', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司製造產品之實際工資率為每人工小時$97，X1 年度實際人工小時數為 9,000 小時，人 工效率差異$47,000（不利），以及工資率差異$27,000（有利），標準人工小時數為何？', '["8,500小時", "8,530小時", "9,470小時", "9,500小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00308', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '乙公司X7年產品單位售價為$55，單位變動成本為$25，固定成本為$200,000，總共銷售10,000 單位，則X7年營業槓桿度為何？', '["0", "0.3", "3", "5.5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00309', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '下列為甲公司今年度之靜態預算及實際產銷量資料如下： 靜態預算 實際資料 單位數 100單位 80單位 單位標準變動成本 直接原料 $10 $10 加工成本 $5 $7 固定成本 設備折舊 $700 $700 有關靜態預算差異與彈性預算差異，下列敘述何者正確？', '["靜態預算不利差異$120，彈性預算有利差異$140", "靜態預算有利差異$120，彈性預算不利差異$140", "靜態預算不利差異$140，彈性預算有利差異$160", "靜態預算有利差異$140，彈性預算不利差異$160"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00310', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司的變動費用占銷貨收入的72%。該公司的損益兩平銷售額為$4,900,000。若該公司目前 銷售額比損益兩平銷售額少$120,000，則淨利（損）為何？', '["淨損$120,000", "淨損$86,400", "淨損$33,600", "淨利$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00311', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '甲公司X8年度的固定製造費用為$12,000，正常產能水準為2,000單位，實際產量為1,500單 位，銷售量為1,200單位，期初存貨為0。該公司採用全部（歸納）成本法，固定製造費用分 攤率係根據正常產能水準計算而得，假設甲公司的實際產量與正常產能的差異屬於重大差異。 下列敘述何者錯誤？', '["全部成本法下固定製造費用包含在期末存貨中的金額為$1,800", "變動成本法下的營業淨利比全部成本法下的營業淨利少$1,800", "全部成本法下，固定製造費用計入損益表的總金額為$7,200", "變動成本法下的固定製造費用計入損益表的總金額為$12,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00312', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '丙公司正在考慮一個投資新設備的資本預算方案，此方案的原始投資額為$186,000， 設備使 用年限為9年，預計運作新設備每年之現金固定成本為$82,000，現金變動成本為收入之5%。 該投資每年產生的現金收入為$180,000，預期之報酬率為6％。則該方案的回收期間多長？', '["7.50 年", "4.31年", "3.25年", "2.09年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00313', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-02588c88', 'sub-pukao-d0d1b9a2-05', NULL, 'single_choice', '丁公司正評估購買新生產設備之計畫，假設新生產設備之成本為$430,000，預計使用年限 8 年，依直線法折舊，殘值為零。若該新生產設備每年年底可創造$110,000 之現金流入，所得 稅率為30%，稅後必要報酬率為12% （8年期$1之複利現值折現因子=0.404、年金現值折現 因子=4.968），則該購買新生產設備計畫之淨現值為何？', '["($8,544)", "$8,592", "$26,580", "$32,645"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "e5bca331583b", "answer_pdf_sha1": "f18827cadf57", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
